mapper.select:
SELECT ar.alarm_rule_id AS alarmRuleId, ar.instance_id AS instanceId, ar.database_id AS databaseId, COALESCE(i.instance_name, 'Unknown') AS instanceName, COALESCE(d.database_name, 'Unknown') AS databaseName, CASE WHEN ar.metric_type LIKE '%vacuum%' OR ar.metric_type LIKE '%dead_tuples%' THEN 'vacuum' WHEN ar.metric_type LIKE '%bloat%' THEN 'bloat' WHEN ar.metric_type LIKE '%wal%' THEN 'wal' ELSE 'session' END AS section, ar.metric_type AS metricType, COALESCE(ar.enabled, false) AS enabled FROM alarm_rule ar LEFT JOIN ( SELECT instance_id, instance_name FROM monitor_instance ) i ON ar.instance_id = i.instance_id LEFT JOIN ( SELECT database_id, database_name FROM monitor_database ) d ON ar.database_id = d.database_id WHERE 1=1
AND ar.instance_id = #{instanceId}
AND ar.database_id = #{databaseId}
AND ar.metric_type = #{metricType}
AND ar.enabled = #{enabled}
ORDER BY ar.created_at DESC

mapper.update:
UPDATE alarm_rule SET levels = CAST(#{levels} AS JSONB), aggregation_type = #{aggregationType}, enabled = #{enabled},
operator = #{operator},
updated_at = NOW() WHERE alarm_rule_id = #{alarmRuleId}

mapper.delete:
WITH deleted_rules AS (
DELETE FROM alarm_rule
WHERE alarm_rule_id = #{alarmRuleId}
    RETURNING alarm_rule_id
)
DELETE FROM alarm_rule
WHERE alarm_rule_id = #{alarmRuleId}

mapper.select:
SELECT alarm_rule_id AS alarmRuleId, instance_id AS instanceId, database_id AS databaseId, metric_type AS metricType, aggregation_type AS aggregationType, operator, levels, enabled FROM alarm_rule WHERE enabled = true AND metric_type = #{metricType}
AND (instance_id = #{instanceId} OR instance_id IS NULL)
AND (database_id = #{databaseId} OR database_id IS NULL)

SELECT COUNT(*)
FROM alarm_rule
WHERE instance_id = #{instanceId}
  AND database_id = #{databaseId}
  AND metric_type = #{metricType}
